  new ParseFilePipeBuilder()
    .addFileTypeValidator({
      fileType: 'jpeg', // Accepts 'image/jpeg'
    })
    .addMaxSizeValidator({
      maxSize: 1000 // Max 1KB
    })
    .build({
      errorHttpStatusCode: 422, // Custom status code (e.g., HttpStatus.UNPROCESSABLE_ENTITY)
      fileIsRequired: false // Make file upload optional
    }),
)
file?: Express.Multer.File, // Note: type changed to optional
