### Bootstrap NestJS Application for AWS Lambda Handler

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/faq/serverless.md

Create the main.ts entry point that bootstraps a NestJS application and exports an AWS Lambda handler function. The handler uses serverless-express to wrap the NestJS Express adapter, enabling the application to process Lambda events and API Gateway requests.

```typescript
import { NestFactory } from '@nestjs/core';
import serverlessExpress from '@codegenie/serverless-express';
import { Callback, Context, Handler } from 'aws-lambda';
import { AppModule } from './app.module';

let server: Handler;

async function bootstrap(): Promise<Handler> {
  const app = await NestFactory.create(AppModule);
  await app.init();

  const expressApp = app.getHttpAdapter().getInstance();
  return serverlessExpress({ app: expressApp });
}

export const handler: Handler = async (
  event: any,
  context: Context,
  callback: Callback,
) => {
  server = server ?? (await bootstrap());
  return server(event, context, callback);
};
```
